parameters.jsCode:
// Process ALL items — loop over all 3
const results = [];

for (const item of $input.all()) {
  const promptText = item.json.veoPrompt;
  const negativePrompt = item.json.negativePrompt || '';

  const requestBody = {
    instances: [{ prompt: promptText }],
    parameters: {
      aspectRatio: "9:16",
      sampleCount: 1,
      durationSeconds: "8",
      personGeneration: "allow_all",
      addWatermark: false,
      includeRaiReason: true,
      generateAudio: true,
      resolution: "720p",
      negativePrompt: negativePrompt
    }
  };

  results.push({ json: { veoRequestBody: requestBody, veoPrompt: promptText } });
}

return results;

